 208→interface QuicklinkFormState {
 209→  name: string;
 210→  link: string;
 211→  type: QuicklinkType;
 212→  application: string;
 213→}
 214→
 215→const INITIAL_FORM: QuicklinkFormState = {
 216→  name: '',
 217→  link: '',
 218→  type: 'url',
 219→  application: '',
 220→};
 221→
 222→const TYPE_OPTIONS = [
 223→  {
 224→    label: 'URL',
 225→    value: 'url',
 226→  },
 227→  {
 228→    label: 'File Path',
 229→    value: 'file',
 230→  },
