 237→interface EditQuicklinkViewProps {
 238→  quicklink?: QuicklinkEntry;
 239→  onSubmit: (form: QuicklinkFormState) => void;
 240→}
 241→
 242→function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
 243→  const [form, setForm] = useState<QuicklinkFormState>(() => {
 244→    if (quicklink) {
 245→      return {
 246→        name: quicklink.name,
 247→        link: quicklink.link,
 248→        type: quicklink.type,
 249→        application: quicklink.application ?? '',
 250→      };
 251→    }
 252→    return INITIAL_FORM;
 253→  });
 254→  const [errors, setErrors] = useState<
 255→    Partial<Record<keyof QuicklinkFormState, string>>
 256→  >({});
 257→
 258→  const handleSubmit = useCallback(() => {
 259→    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
 260→    if (!form.name.trim()) {
 261→      newErrors.name = 'Name is required';
 262→    }
 263→    if (!form.link.trim()) {
 264→      newErrors.link = 'Link is required';
 265→    }
 266→    setErrors(newErrors);
 267→    if (Object.keys(newErrors).length > 0) return;
 268→    onSubmit(form);
 269→  }, [
 270→    form,
 271→    onSubmit,
 272→  ]);
 273→
 274→  useKeyboardShortcut(
 275→    {
 276→      key: 'Enter',
 277→      meta: true,
 278→    },
 279→    handleSubmit,
 280→  );
 281→
 282→  return (
 283→    <Form onSubmit={handleSubmit}>
 284→      <FormTextField
 285→        label="Name"
 286→        value={form.name}
 287→        onChange={v =>
 288→          setForm(prev => ({
 289→            ...prev,
 290→            name: v,
 291→          }))
 292→        }
 293→        placeholder="e.g. GitHub Dashboard"
 294→        error={errors.name}
 295→        autoFocus
 296→      />
 297→      <FormTextField
 298→        label="Link"
 299→        value={form.link}
 300→        onChange={v =>
 301→          setForm(prev => ({
 302→            ...prev,
 303→            link: v,
 304→          }))
 305→        }
 306→        placeholder="e.g. https://github.com or ~/Documents"
 307→        description="Use {query} as placeholder for dynamic input"
 308→        error={errors.link}
 309→      />
 310→      <FormDropdown
 311→        label="Type"
 312→        value={form.type}
 313→        onChange={v => {
 314→          if (isQuicklinkType(v)) {
 315→            setForm(prev => ({
 316→              ...prev,
 317→              type: v,
 318→            }));
 319→          }
 320→        }}
 321→        options={TYPE_OPTIONS}
 322→      />
 323→      <FormTextField
 324→        label="Open With"
 325→        value={form.application}
 326→        onChange={v =>
 327→          setForm(prev => ({
 328→            ...prev,
 329→            application: v,
 330→          }))
 331→        }
 332→        placeholder="e.g. Safari (optional)"
 333→        description="Application to open the link with"
 334→      />
 335→    </Form>
 336→  );
 337→}
