 339→interface QueryInputViewProps {
 340→  quicklink: QuicklinkEntry;
 341→  onSubmit: (resolvedUrl: string) => void;
 342→  onCancel: () => void;
 343→}
 344→
 345→function QueryInputView({
 346→  quicklink,
 347→  onSubmit,
 348→  onCancel,
 349→}: QueryInputViewProps) {
 350→  const [inputValue, setInputValue] = useState('');
 351→
 352→  const handleSubmit = useCallback(() => {
 353→    if (!inputValue.trim()) return;
 354→    const resolved = quicklink.link.replace(
 355→      '{query}',
 356→      encodeURIComponent(inputValue.trim()),
 357→    );
 358→    onSubmit(resolved);
 359→  }, [
 360→    inputValue,
 361→    quicklink.link,
 362→    onSubmit,
 363→  ]);
 364→
 365→  useKeyboardShortcut(
 366→    {
 367→      key: 'Enter',
 368→      meta: true,
 369→    },
 370→    handleSubmit,
 371→  );
 372→  useKeyboardShortcut({ key: 'Escape' }, onCancel);
 373→
 374→  return (
 375→    <Form onSubmit={handleSubmit}>
 376→      <FormTextField
 377→        label="Query"
 378→        value={inputValue}
 379→        onChange={setInputValue}
 380→        placeholder={`Enter query for ${quicklink.name}...`}
 381→        description={`Opens: ${quicklink.link.replace('{query}', '<your input>')}`}
 382→        autoFocus
 383→      />
 384→    </Form>
 385→  );
 386→}
 387→
 388→function openQuicklink(link: string, type: QuicklinkType) {
 389→  if (type === 'url') {
 390→    openUrl(link);
 391→  }
 392→}
