121→const PIN_STATE_KEY = 'clipboard-pins';
122→const DELETED_KEY = 'clipboard-deleted';
123→
124→function loadInitialEntries(): ClipboardEntry[] {
125→  const pinState = storageGet(PIN_STATE_KEY, isBooleanRecord) ?? {};
126→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
127→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
128→    ...e,
129→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
130→  }));
131→}
132→
133→function saveEntryState(entries: ClipboardEntry[]) {
134→  const pinState: Record<string, boolean> = {};
135→  for (const e of entries) {
136→    pinState[e.id] = e.pinned;
137→  }
138→  storageSet(PIN_STATE_KEY, pinState);
139→
140→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
141→  const currentIds = new Set(entries.map(e => e.id));
142→  const deleted = [...allIds].filter(id => !currentIds.has(id));
143→  storageSet(DELETED_KEY, deleted);
144→}
