 1→function isWebUrl(url: string): boolean {
 2→  try {
 3→    const parsed = new URL(url);
 4→    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
 5→  } catch {
 6→    return false;
 7→  }
 8→}
 9→
10→export async function openUrl(url: string): Promise<void> {
11→  if (!isWebUrl(url)) return;
12→  window.open(url, '_blank', 'noopener,noreferrer');
13→}
